from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetMediaNode(BaseNode):
    name = "Prism: Get Media"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity", "dict")
        self.add_output("media", "list")
        self.add_output("count", "int")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        entity = inputs.get('entity') or {}
        if core is None:
            self.log_error("No PrismCore found. Add a prism_core_init node to your graph and connect its exec_out before this node.")
            return {'media': [], 'count': 0}
        try:
            media_module = getattr(core, 'mediaProducts', None) or getattr(core, 'media', None)
            if media_module is None:
                self.log_error("No media module on this PrismCore.")
                return {'media': [], 'count': 0}
            media = []
            for attr in ('getMediaProductsFromEntity', 'getMedia', 'getMediaProducts'):
                if hasattr(media_module, attr):
                    media = getattr(media_module, attr)(entity) or []
                    break
            self.log_info(f"Found {len(media)} media item(s).")
            return {'media': list(media), 'count': len(media)}
        except Exception as e:
            self.log_error(f"getMedia failed: {e}")
            return {'media': [], 'count': 0}

def register_node():
    return PrismGetMediaNode
